//! High-level host library for running Python code in hyperlight-wasm sandboxes.
//!
//! Uses the component model with typed bindings generated by
//! `hyperlight_component_macro::host_bindgen!`.

#![allow(renamed_and_removed_lints)]
#![allow(unknown_lints)]
#![allow(unused_unit)]

extern crate alloc;

use std::collections::HashMap;
use std::path::Path;
use std::sync::Arc;

use anyhow::{Context, Result};
use hyperlight_wasm::{LoadedWasmSandbox, SandboxBuilder};
pub use hyperlight_wasm::Snapshot;
use serde::{Deserialize, Serialize};

// ---------------------------------------------------------------------------
// Component model bindings (generated from the WIT)
// ---------------------------------------------------------------------------

mod bindings {
    hyperlight_component_macro::host_bindgen!("../python_sandbox/wit/python-sandbox-world.wasm");
}

mod wasi_impl;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

/// Configuration for building a [`PythonSandbox`].
pub struct SandboxConfig {
    /// Path to the AOT-compiled Wasm component (e.g. `python-sandbox.aot`).
    pub module_path: String,
    /// Guest heap size in bytes.
    pub heap_size: u64,
    /// Guest scratch / stack size in bytes.
    pub stack_size: u64,
    /// Optional wall-clock timeout (seconds) for guest execution.
    pub timeout_secs: Option<u64>,
}

// ---------------------------------------------------------------------------
// Execution result
// ---------------------------------------------------------------------------

/// The result of executing code inside the sandbox.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ExecutionResult {
    pub stdout: String,
    pub stderr: String,
    pub exit_code: i32,
}

// ---------------------------------------------------------------------------
// Tool registry (Phase 1 stub — functional but not yet wired to host fns)
// ---------------------------------------------------------------------------

/// Registry of host-side tool handlers.
pub struct ToolRegistry {
    tools: HashMap<
        String,
        Box<dyn Fn(serde_json::Value) -> Result<serde_json::Value> + Send + Sync>,
    >,
    middleware: Vec<Box<dyn Fn(&str, &serde_json::Value) -> Result<()> + Send + Sync>>,
}

impl ToolRegistry {
    pub fn new() -> Self {
        Self {
            tools: HashMap::new(),
            middleware: Vec::new(),
        }
    }

    pub fn register<F>(&mut self, name: &str, handler: F)
    where
        F: Fn(serde_json::Value) -> Result<serde_json::Value> + Send + Sync + 'static,
    {
        self.tools.insert(name.to_string(), Box::new(handler));
    }

    pub fn add_middleware<F>(&mut self, hook: F)
    where
        F: Fn(&str, &serde_json::Value) -> Result<()> + Send + Sync + 'static,
    {
        self.middleware.push(Box::new(hook));
    }

    pub fn dispatch(&self, name: &str, args: serde_json::Value) -> Result<serde_json::Value> {
        for hook in &self.middleware {
            hook(name, &args)?;
        }
        let handler = self
            .tools
            .get(name)
            .ok_or_else(|| anyhow::anyhow!("unknown tool: {}", name))?;
        handler(args)
    }
}

impl Default for ToolRegistry {
    fn default() -> Self {
        Self::new()
    }
}

// ---------------------------------------------------------------------------
// WIT host interface — manual registration for tool dispatch
// ---------------------------------------------------------------------------

// The host_bindgen! macro generates export bindings (Executor trait) but its
// import registration uses Vec<u8> params which hyperlight-wasm's
// register_host_function doesn't support. So we register `dispatch` manually
// with String params and use the macro only for export calls.

/// Host state — implements tools.dispatch routing to ToolRegistry.
pub struct HostState {
    tools: ToolRegistry,
}

#[allow(refining_impl_trait)]
impl bindings::root::component::RootImports for HostState {
    type Tools = HostState;
    fn tools(&mut self) -> &mut Self { self }

    type Environment = HostState;
    fn environment(&mut self) -> &mut Self { self }

    type Exit = HostState;
    fn exit(&mut self) -> &mut Self { self }

    type Error = HostState;
    fn error(&mut self) -> &mut Self { self }

    type Poll = HostState;
    fn poll(&mut self) -> &mut Self { self }

    type Streams = HostState;
    fn streams(&mut self) -> &mut Self { self }

    type Stdin = HostState;
    fn stdin(&mut self) -> &mut Self { self }

    type Stdout = HostState;
    fn stdout(&mut self) -> &mut Self { self }

    type Stderr = HostState;
    fn stderr(&mut self) -> &mut Self { self }

    type TerminalInput = HostState;
    fn terminal_input(&mut self) -> &mut Self { self }

    type TerminalOutput = HostState;
    fn terminal_output(&mut self) -> &mut Self { self }

    type TerminalStdin = HostState;
    fn terminal_stdin(&mut self) -> &mut Self { self }

    type TerminalStdout = HostState;
    fn terminal_stdout(&mut self) -> &mut Self { self }

    type TerminalStderr = HostState;
    fn terminal_stderr(&mut self) -> &mut Self { self }

    type MonotonicClock = HostState;
    fn monotonic_clock(&mut self) -> &mut Self { self }

    type WallClock = HostState;
    fn wall_clock(&mut self) -> &mut Self { self }

    type Types = HostState;
    fn types(&mut self) -> &mut Self { self }

    type Preopens = HostState;
    fn preopens(&mut self) -> &mut Self { self }

    type Network = HostState;
    fn network(&mut self) -> &mut Self { self }

    type InstanceNetwork = HostState;
    fn instance_network(&mut self) -> &mut Self { self }

    type Udp = HostState;
    fn udp(&mut self) -> &mut Self { self }

    type UdpCreateSocket = HostState;
    fn udp_create_socket(&mut self) -> &mut Self { self }

    type Tcp = HostState;
    fn tcp(&mut self) -> &mut Self { self }

    type TcpCreateSocket = HostState;
    fn tcp_create_socket(&mut self) -> &mut Self { self }

    type IpNameLookup = HostState;
    fn ip_name_lookup(&mut self) -> &mut Self { self }

    type Random = HostState;
    fn random(&mut self) -> &mut Self { self }

    type Insecure = HostState;
    fn insecure(&mut self) -> &mut Self { self }

    type InsecureSeed = HostState;
    fn insecure_seed(&mut self) -> &mut Self { self }
}

impl bindings::hyperlight::sandbox::Tools for HostState {
    fn dispatch(&mut self, request_json: String) -> String {
        let request: serde_json::Value = serde_json::from_str(&request_json)
            .unwrap_or(serde_json::Value::Null);
        let name = request["name"].as_str().unwrap_or("");
        let args = request.get("args").cloned().unwrap_or(serde_json::Value::Null);
        match self.tools.dispatch(name, args) {
            Ok(v) => serde_json::to_string(&serde_json::json!({"result": v}))
                .unwrap_or_else(|_| r#"{"error":"serialization failed"}"#.to_string()),
            Err(e) => serde_json::to_string(&serde_json::json!({"error": e.to_string()}))
                .unwrap_or_else(|_| r#"{"error":"serialization failed"}"#.to_string()),
        }
    }
}

// ---------------------------------------------------------------------------
// PythonSandbox
// ---------------------------------------------------------------------------

/// A ready-to-use Python execution sandbox backed by hyperlight-wasm.
pub struct PythonSandbox {
    sandbox: bindings::RootSandbox<HostState, LoadedWasmSandbox>,
}

impl PythonSandbox {
    /// Build a new sandbox from the given configuration.
    pub fn new(config: SandboxConfig) -> Result<Self> {
        Self::with_tools(config, ToolRegistry::new())
    }

    /// Build a new sandbox with pre-registered tools.
    pub fn with_tools(config: SandboxConfig, tools: ToolRegistry) -> Result<Self> {
        let module_path = config.module_path.clone();
        let state = HostState { tools };

        let mut proto = SandboxBuilder::new()
            .with_guest_input_buffer_size(70_000_000)
            .with_guest_heap_size(config.heap_size)
            .with_guest_scratch_size(config.stack_size as usize)
            .build()
            .context("failed to build ProtoWasmSandbox")?;

        // register_host_functions binds tools.dispatch via the macro-generated code
        let rt = bindings::register_host_functions(&mut proto, state);

        let wasm_sandbox = proto
            .load_runtime()
            .context("failed to load Wasm runtime")?;

        let sb = wasm_sandbox
            .load_module(Path::new(&module_path))
            .context("failed to load Wasm module")?;

        Ok(Self {
            sandbox: bindings::RootSandbox { sb, rt },
        })
    }

    /// Execute Python `code` in the sandbox.
    pub fn run(&mut self, code: &str) -> Result<ExecutionResult> {
        use bindings::hyperlight::sandbox::Executor;

        // The macro-generated run() panics on guest errors (e.g. GPF from
        // stubbed WASI calls). Catch the panic and return it as an error
        // result so callers get a clean ExecutionResult instead of a crash.
        // https://github.com/hyperlight-dev/hyperlight/issues/1316
        let code_owned = code.to_string();
        let sandbox_ptr = &mut self.sandbox as *mut _ as usize;

        // Suppress the default panic hook output while we catch_unwind
        let prev_hook = std::panic::take_hook();
        std::panic::set_hook(Box::new(|_| {}));

        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            let sandbox = unsafe {
                &mut *(sandbox_ptr
                    as *mut bindings::RootSandbox<HostState, LoadedWasmSandbox>)
            };
            sandbox.run(code_owned)
        }));

        // Restore the original panic hook
        std::panic::set_hook(prev_hook);

        match result {
            Ok(wit_result) => Ok(ExecutionResult {
                stdout: wit_result.stdout,
                stderr: wit_result.stderr,
                exit_code: wit_result.exit_code,
            }),
            Err(panic_info) => {
                let msg = if let Some(s) = panic_info.downcast_ref::<String>() {
                    s.clone()
                } else if let Some(s) = panic_info.downcast_ref::<&str>() {
                    s.to_string()
                } else {
                    "sandbox execution failed".to_string()
                };
                Ok(ExecutionResult {
                    stdout: String::new(),
                    stderr: msg,
                    exit_code: -1,
                })
            }
        }
    }

    /// Take a snapshot of the current sandbox state.
    pub fn snapshot(&mut self) -> Result<Arc<Snapshot>> {
        self.sandbox
            .sb
            .snapshot()
            .map_err(|e| anyhow::anyhow!("snapshot failed: {e}"))
    }

    /// Restore the sandbox to a previously captured snapshot.
    pub fn restore(&mut self, snapshot: &Arc<Snapshot>) -> Result<()> {
        self.sandbox
            .sb
            .restore(snapshot.clone())
            .map_err(|e| anyhow::anyhow!("restore failed: {e}"))
    }
}
